@EventTarget
public void onPacketReceive(EventReceivePacket event) {
    if (event.getPacket() instanceof S29PacketSoundEffect) {
        S29PacketSoundEffect s29 = (S29PacketSoundEffect) event.getPacket();
        String name = s29.getSoundName();
        double x = s29.getX() / 8.0;
        double y = s29.getY() / 8.0;
        double z = s29.getZ() / 8.0;
        float volume = s29.getVolume();

        // Track recent sounds for ESP
        recentSounds.add(new SoundEntry(name, x, y, z, volume, System.currentTimeMillis()));

        // Creeper hiss detection
        if (name.equals("mob.creeper.primed")) {
            // Creeper behind wall at (x, y, z)
            lastCreeperSound = new Vec3(x, y, z);
        }

        // Fishing bite detection
        if (name.equals("random.splash") && mc.thePlayer.fishEntity != null) {
            if (mc.thePlayer.getDistance(x, y, z) < 3.0f) {
                mc.thePlayer.fishEntity.caught();
            }
        }

        // Lightning position tracking
        if (name.equals("ambient.weather.thunder")) {
            lastLightningPos = new Vec3(x, y, z);
        }
    }
}

