package net.minecraft.network.play.server;

import net.minecraft.network.Packet;
import net.minecraft.network.PacketBuffer;
import net.minecraft.network.play.INetHandlerPlayClient;
import java.io.IOException;

public class S29PacketSoundEffect implements Packet<INetHandlerPlayClient> {
    private String soundName;
    private int posX, posY, posZ;
    private float volume;
    private int pitch;

    public S29PacketSoundEffect() {}
    public S29PacketSoundEffect(String nameIn, double xIn, double yIn, double zIn,
                                  float volumeIn, float pitchIn) {
        this.soundName = nameIn;
        this.posX = (int)(xIn * 8.0);
        this.posY = (int)(yIn * 8.0);
        this.posZ = (int)(zIn * 8.0);
        this.volume = volumeIn;
        this.pitch = (int)(pitchIn * 63.0F);
    }

    public void processPacket(INetHandlerPlayClient handler) { handler.handleSoundEffect(this); }
    public String getSoundName() { return this.soundName; }
    public double getX() { return (double)this.posX / 8.0; }
    public double getY() { return (double)this.posY / 8.0; }
    public double getZ() { return (double)this.posZ / 8.0; }
    public float getVolume() { return this.volume; }
    public float getPitch() { return (float)this.pitch / 63.0F; }
}
